SELECT COUPON_SN, COUPON_NM, DISC_TYPE, DISC_AMT, DISC_RATE, USE_LIMIT_CD, VALID_DAYS, USE_YN, REG_USER_ID, REG_DT, COUPON_CODE
FROM COUPON
